"use client";

import { useEditor, EditorContent } from "@tiptap/react";
import StarterKit from "@tiptap/starter-kit";
import Image from "@tiptap/extension-image";
import Link from "@tiptap/extension-link";
import Placeholder from "@tiptap/extension-placeholder";
import CodeBlockLowlight from "@tiptap/extension-code-block-lowlight";
import { common, createLowlight } from "lowlight";
import { Toolbar } from "./toolbar";

const lowlight = createLowlight(common);

interface TiptapEditorProps {
  content?: Record<string, unknown>;
  onChange?: (json: Record<string, unknown>, html: string) => void;
  placeholder?: string;
  editable?: boolean;
  onImageUpload?: (file: File) => Promise<string>;
}

export function TiptapEditor({
  content,
  onChange,
  placeholder = "Begin met schrijven...",
  editable = true,
  onImageUpload,
}: TiptapEditorProps) {
  const editor = useEditor({
    extensions: [
      StarterKit.configure({
        codeBlock: false, // Use CodeBlockLowlight instead
      }),
      Image.configure({
        HTMLAttributes: {
          class: "rounded-lg max-w-full mx-auto",
        },
      }),
      Link.configure({
        openOnClick: false,
        HTMLAttributes: {
          class: "text-primary underline hover:text-primary/80",
        },
      }),
      Placeholder.configure({
        placeholder,
      }),
      CodeBlockLowlight.configure({
        lowlight,
        HTMLAttributes: {
          class: "bg-muted rounded-lg p-4 font-mono text-sm",
        },
      }),
    ],
    content: content as Record<string, unknown> | undefined,
    editable,
    onUpdate: ({ editor: e }) => {
      const json = e.getJSON() as Record<string, unknown>;
      const html = e.getHTML();
      onChange?.(json, html);
    },
    editorProps: {
      attributes: {
        class:
          "prose prose-sm sm:prose-base max-w-none focus:outline-none min-h-[300px] px-4 py-3 text-foreground",
      },
    },
  });

  if (!editor) return null;

  return (
    <div className="rounded-lg border border-border bg-white">
      {editable && (
        <Toolbar editor={editor} onImageUpload={onImageUpload} />
      )}
      <EditorContent editor={editor} />
    </div>
  );
}
